// frontend/src/components/Auth/Register.js
import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton,
  Tooltip,
  List,
  ListItem,
  ListItemIcon,
  ListItemText
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Person,
  Email,
  Lock,
  VpnKey,
  Security,
  Check,
  Close,
  Info,
  Key
} from '@mui/icons-material';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import authService from '../../services/authService';

const Register = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    password: '',
    confirmPassword: '',
    bitget_api_key: '',
    bitget_api_secret: '',
    bitget_passphrase: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [showApiSecret, setShowApiSecret] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [passwordValidation, setPasswordValidation] = useState({
    length: false,
    uppercase: false,
    lowercase: false,
    number: false,
    special: false
  });

  // Estado para controlar se o usuário tem permissão para se cadastrar
  const [hasPaymentAccess, setHasPaymentAccess] = useState(false);

  // Verificar se há parâmetro de acesso na URL (vindo do webhook do Hubla)
  React.useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const accessToken = urlParams.get('access_token');
    const paymentConfirmed = urlParams.get('payment_confirmed');

    if (accessToken && paymentConfirmed === 'true') {
      setHasPaymentAccess(true);
      // Limpar os parâmetros da URL
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Validação em tempo real da senha
    if (name === 'password') {
      validatePassword(value);
    }

    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const validatePassword = (password) => {
    setPasswordValidation({
      length: password.length >= 8,
      uppercase: /[A-Z]/.test(password),
      lowercase: /[a-z]/.test(password),
      number: /\d/.test(password),
      special: /[@$!%*?&_\-]/.test(password)
    });
  };

  const isPasswordValid = () => {
    return Object.values(passwordValidation).every(Boolean);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Verificar se o usuário tem acesso de pagamento
    if (!hasPaymentAccess) {
      setError('Acesso negado. Você precisa efetuar o pagamento para se cadastrar.');
      setLoading(false);
      return;
    }

    // Validações
    const { full_name, email, password, confirmPassword, bitget_api_key, bitget_api_secret, bitget_passphrase } = formData;

    if (!full_name || !email || !password || !confirmPassword || !bitget_api_key || !bitget_api_secret || !bitget_passphrase) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    if (!authService.validateEmail(email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    if (!isPasswordValid()) {
      setError('A senha não atende aos requisitos de complexidade');
      setLoading(false);
      return;
    }

    if (password !== confirmPassword) {
      setError('As senhas não coincidem');
      setLoading(false);
      return;
    }

    try {
      const registrationData = {
        full_name,
        email,
        password,
        bitget_api_key,
        bitget_api_secret,
        bitget_passphrase
      };

      await authService.register(registrationData);

      toast.success('Conta criada com sucesso! Faça login para continuar.');
      navigate('/login');
    } catch (error) {
      console.error('Erro no registro:', error);
      setError(error.message || 'Erro ao criar conta. Tente novamente.');
      toast.error(error.message || 'Erro ao criar conta');
    } finally {
      setLoading(false);
    }
  };

  const ValidationIcon = ({ isValid }) => (
    isValid ? <Check sx={{ color: '#02c076', fontSize: 16 }} /> : <Close sx={{ color: '#f84960', fontSize: 16 }} />
  );

  return (
    <Container maxWidth="md">
      <Box
        sx={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          py: 4
        }}
      >
        <Paper
          elevation={8}
          sx={{
            p: 4,
            width: '100%',
            maxWidth: 600,
            bgcolor: 'background.paper',
            borderRadius: 2
          }}
        >
          {/* Logo/Título */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography
              variant="h4"
              component="h1"
              sx={{
                fontWeight: 'bold',
                color: '#1976d2', // Cor azul
                mb: 1
              }}
            >
              Nautilus Automação
            </Typography>
            <Typography
              variant="subtitle1"
              color="text.secondary"
            >
              Crie sua conta de trading
            </Typography>
          </Box>

          {/* Formulário */}
          <Box component="form" onSubmit={handleSubmit}>
            {error && (
              <Alert severity="error" sx={{ mb: 2 }}>
                {error}
              </Alert>
            )}

            {/* Nome Completo */}
            <TextField
              fullWidth
              name="full_name"
              label="Nome Completo"
              value={formData.full_name}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Person color="action" />
                  </InputAdornment>
                ),
              }}
            />

            {/* Email */}
            <TextField
              fullWidth
              name="email"
              label="Email"
              type="email"
              value={formData.email}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email color="action" />
                  </InputAdornment>
                ),
              }}
            />

            {/* Senha */}
            <TextField
              fullWidth
              name="password"
              label="Senha"
              type={showPassword ? 'text' : 'password'}
              value={formData.password}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => setShowPassword(!showPassword)}
                      edge="end"
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* Validação da senha */}
            {formData.password && (
              <Box sx={{ mt: 1, mb: 2 }}>
                <Typography variant="caption" color="text.secondary" sx={{ mb: 1, display: 'block' }}>
                  Requisitos da senha:
                </Typography>
                <List dense sx={{ py: 0 }}>
                  <ListItem sx={{ py: 0, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 24 }}>
                      <ValidationIcon isValid={passwordValidation.length} />
                    </ListItemIcon>
                    <ListItemText 
                      primary="Pelo menos 8 caracteres" 
                      primaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                  <ListItem sx={{ py: 0, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 24 }}>
                      <ValidationIcon isValid={passwordValidation.uppercase} />
                    </ListItemIcon>
                    <ListItemText 
                      primary="Uma letra maiúscula" 
                      primaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                  <ListItem sx={{ py: 0, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 24 }}>
                      <ValidationIcon isValid={passwordValidation.lowercase} />
                    </ListItemIcon>
                    <ListItemText 
                      primary="Uma letra minúscula" 
                      primaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                  <ListItem sx={{ py: 0, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 24 }}>
                      <ValidationIcon isValid={passwordValidation.number} />
                    </ListItemIcon>
                    <ListItemText 
                      primary="Um número" 
                      primaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                  <ListItem sx={{ py: 0, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 24 }}>
                      <ValidationIcon isValid={passwordValidation.special} />
                    </ListItemIcon>
                    <ListItemText 
                      primary="Um caractere especial (@$!%*?&_-)" 
                      primaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                </List>
              </Box>
            )}

            {/* Confirmar Senha */}
            <TextField
              fullWidth
              name="confirmPassword"
              label="Confirmar Senha"
              type={showConfirmPassword ? 'text' : 'password'}
              value={formData.confirmPassword}
              onChange={handleChange}
              margin="normal"
              required
              error={!!(formData.confirmPassword && formData.password !== formData.confirmPassword)}
              helperText={
                formData.confirmPassword && formData.password !== formData.confirmPassword
                  ? 'As senhas não coincidem'
                  : ''
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                      edge="end"
                    >
                      {showConfirmPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* API Key da Bitget */}
            <TextField
              fullWidth
              name="bitget_api_key"
              label="Bitget API Key"
              value={formData.bitget_api_key}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <VpnKey color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <Tooltip title="Sua chave de API da Bitget para acessar dados de trading">
                      <Info color="action" />
                    </Tooltip>
                  </InputAdornment>
                ),
              }}
            />

            {/* API Secret da Bitget */}
            <TextField
              fullWidth
              name="bitget_api_secret"
              label="Bitget API Secret"
              type={showApiSecret ? 'text' : 'password'}
              value={formData.bitget_api_secret}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Security color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => setShowApiSecret(!showApiSecret)}
                      edge="end"
                    >
                      {showApiSecret ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* Passphrase da Bitget */}
            <TextField
              fullWidth
              name="bitget_passphrase"
              label="Bitget Passphrase"
              value={formData.bitget_passphrase}
              onChange={handleChange}
              margin="normal"
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <Tooltip title="Passphrase da sua API Bitget (obrigatório para autenticação)">
                      <Info color="action" />
                    </Tooltip>
                  </InputAdornment>
                ),
              }}
            />



            {/* Aviso de segurança */}
            <Alert severity="info" sx={{ mt: 2, mb: 2 }}>
              <Typography variant="caption">
                🔒 Suas credenciais da API são criptografadas com AES-256 e armazenadas com segurança.
                Nunca compartilhe suas chaves de API com terceiros.
              </Typography>
            </Alert>

            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading || !isPasswordValid()}
              sx={{
                mt: 3,
                mb: 2,
                py: 1.5,
                fontSize: '1rem',
                fontWeight: 'bold',
                bgcolor: 'primary.main',
                color: 'black',
                '&:hover': {
                  bgcolor: 'primary.dark',
                },
                '&:disabled': {
                  bgcolor: 'action.disabled',
                },
              }}
            >
              {loading ? (
                <CircularProgress size={24} color="inherit" />
              ) : (
                'Criar Conta'
              )}
            </Button>

            {/* Link para login */}
            <Box sx={{ textAlign: 'center', mt: 2 }}>
              <Typography variant="body2" color="text.secondary">
                Já tem uma conta?{' '}
                <Link
                  component={RouterLink}
                  to="/login"
                  sx={{
                    color: 'primary.main',
                    textDecoration: 'none',
                    fontWeight: 'bold',
                    '&:hover': {
                      textDecoration: 'underline',
                    },
                  }}
                >
                  Faça login
                </Link>
              </Typography>
            </Box>
          </Box>
        </Paper>
      </Box>
    </Container>
  );
};

export default Register;
